"""
Revised plan post-transform — aligned to Transform Js Scripts/Revised_Plan.js
(convertRevisedPlanCustomerCSVToParamCSV + convertJson).
Doc id: RP_MM_YYYY (not REV). I_ScheduleQuantity uses RW1–RW5; I_Quantity from Total column.
"""
import hashlib
import re
from datetime import datetime, timedelta

_RW_COL = re.compile(r"^RW([1-5])\b", re.IGNORECASE)
