def _hash_id_hex(s: str) -> str:
    try:
        from Crypto.Hash import keccak
        h = keccak.new(digest_bits=256)
        h.update(s.encode("utf-8"))
        return "0x" + h.hexdigest()
    except ImportError:
        return "0x" + hashlib.sha256(s.encode("utf-8")).hexdigest()


def _ts_ms(dt=None):
    d = dt if dt is not None else datetime.now()
    return int(d.timestamp() * 1000)


def _add_zeros(thk: str) -> str:
    if not thk:
        return "0.000"
    try:
        return f"{float(thk):.3f}"
    except (ValueError, TypeError):
        return thk


def _item_name_js(unit: str, gade: str, width: str, thk_str: str) -> str:
    """Same as tentative_plan.js / Revised_Plan.js."""
    unit_l = (unit or "").strip().lower()
    gade_l = (gade or "").strip().lower()
    w = (width or "").replace(",", "").strip()
    thk = _add_zeros((thk_str or "").strip())
    if unit_l == "unit 1" and gade_l == "lpa":
        return f"R468P10-1050H18-0-{w}-{thk}"
    if unit_l == "p5":
        if gade_l == "lph hi-uts":
            return f"R46E810-1050H18-0-{w}-{thk}"
        if gade_l == "v1s":
            return f"R46E810-VISH18-0-{w}-{thk}"
        if gade_l == "lpa":
            return f"R468P10-1050H18-0-{w}-{thk}"
    return ""


def _parse_int(val) -> int:
    if not val or str(val).strip() in ("", "-", "0"):
        return 0
    try:
        return int(float(str(val).replace(",", "").strip()))
    except (ValueError, TypeError):
        return 0


def _rw_weeks(row: dict):
    """JS destructures RW1–RW5 from row (column headers like 'RW1 (0-7)')."""
    out = [0, 0, 0, 0, 0]
    for key, val in row.items():
        m = _RW_COL.match((key or "").strip())
        if m:
            out[int(m.group(1)) - 1] = _parse_int(val)
    return out


def _total_qty_js(row: dict) -> int:
    """JS: Rtotal / Total column."""
    t = row.get("Rtotal", row.get("Total", ""))
    if t is None or str(t).strip() in ("", "-"):
        return 0
    return _parse_int(t)


def _backlog_js(backlog_str: str):
    b = (backlog_str or "").strip()
    if b == "-":
        return None
    if not b:
        return 0
    return _parse_int(b)


def _ordered_date_ms(imported_year, imported_month, day="02") -> int:
    y = int(imported_year)
    m = int(imported_month)
    d = int(day)
    return int(datetime(y, m, d).timestamp() * 1000)


def _event_schedule_revised_js():
    """JS Revised lines 127-128: getSatrtDate/getEndDate on date(year, importedMonth, new Date().getDate())."""
    now = datetime.now()
    year = now.year
    month = now.month
    day = now.day
    try:
        anchor = datetime(year, month, day)
    except ValueError:
        anchor = now
    y, m = anchor.year, anchor.month
    start = datetime(y, m, 1)
    if m == 12:
        end = datetime(y + 1, 1, 1) - timedelta(days=1)
    else:
        end = datetime(y, m + 1, 1) - timedelta(days=1)
    return (
        f"{start.year}-{start.month}-{start.day}",
        f"{end.year}-{end.month}-{end.day}",
    )


def _revised_order_number(doc: dict, imported_month: str, imported_year: str) -> str:
    """Own doc id is RP_MM_YYYY. Ignore inherited Contract/Tentative DocNumber on chained doc."""
    fallback = f"RP_{imported_month}_{imported_year}"
    for key in ("docNumber", "doc_number", "DocNumber"):
        v = doc.get(key)
        if not v:
            continue
        s = str(v).strip()
        if s.upper().startswith("RP_"):
            return s
    rows = doc.get("line_items") or []
    if rows and isinstance(rows[0], dict):
        for col in ("DocNumber", "docNumber"):
            v = rows[0].get(col)
            if v and str(v).strip().upper().startswith("RP_"):
                return str(v).strip()
    return fallback


def _tentative_parent_ref(doc: dict, imported_month: str, imported_year: str) -> str:
    """Revised parent is TentativePlan TP_MM_YYYY, not CONTRACT001."""
    fallback = f"TP_{imported_month}_{imported_year}"
    v = doc.get("parentDocNumber")
    if v:
        s = str(v).strip()
        if s.upper().startswith("TP_"):
            return s
    return fallback


def run(doc: dict) -> dict:
    rows = doc.get("line_items")
    if not rows and "__raw_json" in doc:
        try:
            import json
            raw_obj = json.loads(doc["__raw_json"])
            rows = raw_obj.get("line_items")
        except Exception as e:
            print(f"[WARN] Failed to parse __raw_json: {e}")

    if not rows:
        rows = [doc]

    imported_year = str(doc.get("importedYear", datetime.now().year))
    imported_month = str(doc.get("importedMonth", datetime.now().strftime("%m"))).zfill(2)
    order_number = _revised_order_number(doc, imported_month, imported_year)
    tp_parent = _tentative_parent_ref(doc, imported_month, imported_year)

    ordered_items = []
    for row in rows:
        gade = (row.get("Grade") or row.get("Gade") or "").strip()
        unit = (row.get("Unit") or "").strip()
        if not unit or not gade:
            continue

        width_str = (row.get("Width") or "").replace(",", "").strip()
        thk_str = (row.get("Thk") or "").strip()
        backlog_str = (row.get("Backlog") or "").strip()
        remarks = (row.get("Remarks") or "").strip()

        thk = _add_zeros(thk_str)
        name = _item_name_js(unit, gade, width_str, thk_str)
        if not name:
            continue

        rw = _rw_weeks(row)
        w1, w2, w3, w4, w5 = rw
        sched_str = f"{w1},{w2},{w3},{w4},{w5}"
        width_int = int(float(width_str)) if width_str else 0
        qty_total = _total_qty_js(row)

        oid = _hash_id_hex(name)
        ordered_items.append({
            "I_Identifier": oid,
            "I_Name": name,
            "I_Number": name,
            "I_Grade": gade,
            "I_Thickness": thk,
            "I_Width": width_int,
            "I_Quantity": qty_total,
            "I_ScheduleQuantity": sched_str,
            "I_Week1": w1,
            "I_Week2": w2,
            "I_Week3": w3,
            "I_Week4": w4,
            "I_Week5": w5,
            "I_BacklogQuantity": _backlog_js(backlog_str),
            "I_AdditionalProperties": {
                "IA_CustomerPlantRef": unit,
                "IA_Remarks": remarks,
            },
        })

    if not ordered_items:
        print("[WARN] RevisedPlan: no rows matched JS item rules.")
        return doc

    ts = _ts_ms()
    d_ordered = _ordered_date_ms(imported_year, imported_month, "02")
    e_start, e_end = _event_schedule_revised_js()

    res = {
        "DocDetails": {
            "D_OrderNumber": order_number,
            "D_DocumentNumber": order_number,
            "D_OrderedDate": d_ordered,
            "D_DocumentCreationDate": ts,
            "D_Identifier": _hash_id_hex(order_number),
            "D_ParentDocumentNumbers": [tp_parent],
        },
        "_id": _hash_id_hex(order_number),
        "OrderedItems": ordered_items,
        "EventSchedule": {
            "E_StartDate": e_start,
            "E_EndDate": e_end,
        },
        "ReferencesOrder": [
            {
                "R_OrderNumber": tp_parent,
                "R_OrderedDate": _ordered_date_ms(imported_year, imported_month, "02"),
            }
        ],
        "Buyer": BUYER_TECHNOVA,
        "Seller": SELLER_TALOJA,
    }

    return res
